# Unit Tests for `partial` Function

```python
import pytest
from functools import reduce


# Assuming the function is in a module called `utils`
# from utils import partial

def partial(fn, *partial_args, **partial_kwargs):
    def wrapper(*args, **kwargs):
        merged = {**partial_kwargs, **kwargs}
        return fn(*partial_args, *args, **merged)
    return wrapper


# ---------- Helper functions for testing ----------

def add(a, b):
    return a + b


def add_three(a, b, c):
    return a + b + c


def greet(greeting, name, punctuation="."):
    return f"{greeting}, {name}{punctuation}"


def no_args():
    return "no args called"


def kwargs_only(**kwargs):
    return kwargs


def args_only(*args):
    return args


def mixed(a, b, *args, c=10, **kwargs):
    return (a, b, args, c, kwargs)


# ============ HAPPY PATH TESTS ============

class TestHappyPath:
    """Tests for typical, expected usage."""

    def test_partial_with_one_positional_arg(self):
        """Partial application of one positional argument."""
        add_five = partial(add, 5)
        assert add_five(3) == 8

    def test_partial_with_multiple_positional_args(self):
        """Partial application of multiple positional arguments."""
        add_one_two = partial(add_three, 1, 2)
        assert add_one_two(3) == 6

    def test_partial_with_all_positional_args(self):
        """All arguments supplied at partial creation time."""
        full = partial(add, 2, 3)
        assert full() == 5

    def test_partial_with_keyword_args(self):
        """Partial application with keyword arguments."""
        hello = partial(greet, "Hello")
        assert hello("World") == "Hello, World."

    def test_partial_with_both_positional_and_keyword(self):
        """Mix of positional and keyword args at partial-time."""
        excited_hello = partial(greet, "Hello", punctuation="!")
        assert excited_hello("World") == "Hello, World!"

    def test_partial_keyword_overridden_at_call_time(self):
        """Keyword args supplied at call time override partial kwargs."""
        excited_hello = partial(greet, "Hello", punctuation="!")
        assert excited_hello("World", punctuation="?") == "Hello, World?"

    def test_partial_preserves_return_value(self):
        """The wrapper returns the underlying function's return value."""
        double = partial(lambda x: x * 2)
        assert double(7) == 14

    def test_partial_returns_callable(self):
        """The result of partial is callable."""
        result = partial(add, 1)
        assert callable(result)


# ============ EDGE CASE TESTS ============

class TestEdgeCases:
    """Tests for boundary and unusual inputs."""

    def test_partial_with_no_partial_args(self):
        """Partial with no pre-applied args behaves like the original function."""
        f = partial(add)
        assert f(2, 3) == 5

    def test_partial_with_no_call_args(self):
        """Partial with all args and no call args."""
        f = partial(no_args)
        assert f() == "no args called"

    def test_partial_with_only_kwargs(self):
        """Partial wrapping a kwargs-only function."""
        f = partial(kwargs_only, a=1, b=2)
        assert f() == {"a": 1, "b": 2}

    def test_partial_kwargs_merged_with_call_kwargs(self):
        """Partial kwargs and call kwargs are merged."""
        f = partial(kwargs_only, a=1)
        assert f(b=2) == {"a": 1, "b": 2}

    def test_partial_call_kwargs_override_partial_kwargs(self):
        """Call-time kwargs take precedence over partial kwargs."""
        f = partial(kwargs_only, a=1, b=2)
        assert f(a=99) == {"a": 99, "b": 2}

    def test_partial_with_only_args_function(self):
        """Function that takes *args only."""
        f = partial(args_only, 1, 2)
        assert f(3, 4) == (1, 2, 3, 4)

    def test_partial_chained(self):
        """Calling partial on the result of partial works."""
        f = partial(add_three, 1)
        g = partial(f, 2)
        assert g(3) == 6

    def test_partial_can_be_called_multiple_times(self):
        """The wrapper can be called repeatedly with different args."""
        add_ten = partial(add, 10)
        assert add_ten(1) == 11
        assert add_ten(2) == 12
        assert add_ten(3) == 13

    def test_partial_with_complex_signature(self):
        """Function with positional, *args, keyword-only, and **kwargs."""
        f = partial(mixed, 1, 2, c=99)
        result = f(3, 4, extra="yes")
        assert result == (1, 2, (3, 4), 99, {"extra": "yes"})

    def test_partial_with_none_arg(self):
        """None can be a partially applied argument."""
        f = partial(lambda x, y: (x, y), None)
        assert f(5) == (None, 5)

    def test_partial_with_mutable_default(self):
        """Mutable arguments are passed through correctly."""
        lst = [1, 2, 3]
        f = partial(lambda x, y: x + y, lst)
        assert f([4, 5]) == [1, 2, 3, 4, 5]

